define i32 @uadd_sat_canon_y_nuw(i32 %x, i32 %y) {
  %a = add nuw i32 %x, %y
  %c = icmp ult i32 %a, %y
  %r = select i1 %c, i32 -1, i32 %a
  ret i32 %r
}

define i32 @uadd_sat_constant(i32 %x) {
  %a = add i32 %x, 42
  %c = icmp ugt i32 %x, -43
  %r = select i1 %c, i32 -1, i32 %a
  ret i32 %r
}

define i32 @uadd_sat_flipped(i32 %x) {
  %cmp = icmp uge i32 %x, -10
  %add = add i32 %x, 9
  %cond = select i1 %cmp, i32 -1, i32 %add
